namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
    public int RatingCount => Ratings.Count;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute on top.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                Ratings = [5, 4, 5, 4, 5]
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra cheese.",
                Ratings = [5, 5, 4]
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt and spices for 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Add cream and cooked chicken.\n6. Simmer 10 minutes and serve with rice.",
                Ratings = [5, 4, 5, 5]
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nGarlic",
                Steps = "1. Soak rice noodles in warm water 20 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Make sauce: mix tamarind, fish sauce, and sugar.\n4. Stir-fry garlic, add noodles and sauce.\n5. Toss with tofu, bean sprouts, and green onions.\n6. Serve with crushed peanuts and lime wedges.",
                Ratings = [4, 4, 3, 5]
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
                Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Fill tortillas with seasoned beef.\n5. Top with lettuce, tomato, cheese, sour cream, and salsa.",
                Ratings = [4, 5, 4]
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt\nGarlic",
                Steps = "1. Halve and pit avocados, scoop into a bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and cilantro.\n4. Add lime juice, garlic, and salt to taste.\n5. Serve immediately with tortilla chips.",
                Ratings = [5, 5, 5, 4, 5]
            },
            new Recipe
            {
                Id = 7, Title = "Miso Ramen", Category = "Asian",
                Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoy sauce\nSesame oil\nSoft-boiled egg\nGreen onions\nCorn\nNori\nChashu pork",
                Steps = "1. Bring chicken broth to a simmer.\n2. Whisk in miso paste and soy sauce.\n3. Cook ramen noodles separately.\n4. Place noodles in a bowl, ladle broth over.\n5. Top with sliced chashu, soft-boiled egg, corn, nori, and green onions.\n6. Drizzle with sesame oil.",
                Ratings = [5, 4, 5]
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract\nPowdered sugar",
                Steps = "1. Preheat oven to 425°F. Butter and flour ramekins.\n2. Melt chocolate and butter together.\n3. Whisk in eggs, sugar, and vanilla.\n4. Fold in flour gently.\n5. Pour into ramekins and bake 12-14 minutes.\n6. Invert onto plates and dust with powdered sugar.",
                Ratings = [5, 5, 5, 5, 4]
            },
        ];
        _nextId = 9;
    }

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

