arguments.file_text:
@rendermode InteractiveServer

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => Rate(star)"
                title="Rate @star star(s)">
            @(star <= _selectedRating ? "★" : "☆")
        </button>
    }
    @if (_submitted)
    {
        <span class="text-success small ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    [Inject] private Services.RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating;
    private bool _submitted;

    private async Task Rate(int stars)
    {
        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
        await OnRated.InvokeAsync(stars);
    }
}

@rendermode InteractiveServer

@using RecipeCommunity.Services

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="_model.Title" />
