@page "/"

@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1 class="display-4">🍳 Recipe Community</h1>
    <p class="lead text-muted">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        var recipes = RecipeService.GetByCategory(category);
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">@CategoryEmoji(category) @category</h5>
                    <p class="card-text text-muted">@recipes.Count recipe(s)</p>
                    <a href="/category/@category" class="btn btn-outline-primary">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string CategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

