@page "/category/{CategoryName}"

@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1 class="mb-4">@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in _recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            @if (recipe.RatingCount > 0)
                            {
                                <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                                <small class="text-muted">(@recipe.AverageRating.ToString("F1") · @recipe.RatingCount ratings)</small>
                            }
                            else
                            {
                                <small class="text-muted">No ratings yet</small>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@_recipe.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@_recipe.Category</span>

    @if (_recipe.RatingCount > 0)
    {
        <p>
            <span class="text-warning fs-5">@(new string('★', (int)Math.Round(_recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(_recipe.AverageRating)))</span>
            <span class="text-muted">@_recipe.AverageRating.ToString("F1") average · @_recipe.RatingCount ratings</span>
        </p>
    }

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header fw-bold">Ingredients</div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient.Trim()</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Instructions</h4>
            @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step.Trim()</p>
            }
        </div>
    </div>

    <div class="card mt-4">
        <div class="card-body">
            <h5 class="card-title">Rate this recipe</h5>
            <StarRating RecipeId="@_recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

